module RefModule(
    input clk,
    input reset,    
    input j,
    input k,
    output out);parameter OFF=0, ON=1; 
    reg state, ctrl_bus_wire;

    always @(*) begin

        case(state)
            OFF: ctrl_bus_wire = (j)? ON:OFF;
            ON: ctrl_bus_wire = (k)? OFF:ON;
        endcase
    end

    always @(posedge clk) begin

        if (reset)
            state <= OFF;
        else
            state <= ctrl_bus_wire;
    end


    assign out = (state == ON);

endmodule
